+// progressBar renders a text-based progress bar.
+func progressBar(current, total int) string {
+	const width = 40
+	if total == 0 {
+		return "[" + string(make([]byte, width)) + "]"
+	}
+	filled := (current * width) / total
+	bar := ""
+	for i := 0; i < width; i++ {
+		if i < filled {
+			bar += "█"
+		} else {
+			bar += " "
+		}
+	}
+	return "[" + bar + "]"
+}
