-func listenRPC(socketPath string) (net.Listener, error) {
-	listener, err := net.Listen("tcp", "127.0.0.1:0")
-	if err != nil {
-		return nil, err
-	}
-
-	info := endpointInfo{
-		Network: "tcp",
-		Address: listener.Addr().String(),
-	}
-
-	data, err := json.Marshal(info)
-	if err != nil {
-		listener.Close()
-		return nil, err
-	}
-
-	if err := os.WriteFile(socketPath, data, 0o600); err != nil {
-		listener.Close()
-		return nil, err
-	}
-
-	return listener, nil
-}
